class FreqStack {
public:
    FreqStack() {
        freq = 0;
    }

    void push(int val) {
        freqStack[val].push(val);
        freqStack[val].top() == val ? freq++ : freq;
        freqMap[freq]++;
    }

    int pop() {
        int maxFreq = 0;
        for (auto& pair : freqMap) {
            if (pair.second > maxFreq) {
                maxFreq = pair.second;
            }
        }
        int val = freqStack[maxFreq].top();
        freqStack[maxFreq].pop();
        freqMap[maxFreq]--;
        if (freqMap[maxFreq] == 0) {
            freqMap.erase(maxFreq);
        }
        return val;
    }
private:
    int freq;
    unordered_map<int, stack<int>> freqStack;
    unordered_map<int, int> freqMap;
};
```

efficiency: HIGH
time complexity: O(1) amortized for push, O(n) for pop
space complexity: O(n)
